mapper.select:
SELECT id, topic_code, name, description, heat_text, destination_type, accent_tone, emoji, sort_order FROM topics
destination_type = #{scope}
ORDER BY sort_order ASC, id ASC

SELECT t.topic_code, tt.tag_name, tt.sort_order FROM topic_tags tt INNER JOIN topics t ON t.id = tt.topic_id
t.destination_type = #{scope}
ORDER BY t.sort_order ASC, tt.sort_order ASC, tt.id ASC

SELECT

FROM posts p
         LEFT JOIN post_interactions i ON i.post_id = p.id AND i.user_id = #{userId}

    p.audience_type = #{audience}

        AND p.topic_name = #{topic}


        AND (
            p.title LIKE CONCAT('%', #{keyword}, '%')
                OR p.content LIKE CONCAT('%', #{keyword}, '%')
                OR p.author_name LIKE CONCAT('%', #{keyword}, '%')
                OR p.topic_name LIKE CONCAT('%', #{keyword}, '%')
            )


ORDER BY p.created_at DESC, p.id DESC

SELECT

FROM posts p
         LEFT JOIN post_interactions i ON i.post_id = p.id AND i.user_id = #{userId}
WHERE p.creator_user_id = #{userId}
ORDER BY p.created_at DESC, p.id DESC

SELECT

FROM post_comments c
         INNER JOIN posts p ON p.id = c.post_id
WHERE p.post_code = #{postCode}
  AND c.comment_code = #{commentCode}
  AND c.deleted_flag = 0

SELECT m.id, m.message_code, m.conversation_id, c.conversation_code, m.sender_type, m.text_content, m.display_time, m.created_at FROM messages m INNER JOIN conversations c ON c.id = m.conversation_id WHERE c.conversation_code IN
#{code}
ORDER BY m.created_at ASC, m.id ASC

SELECT COUNT(1)
FROM posts
WHERE audience_type = #{audience}
